const shots = Array.isArray(root.shots) ? root.shots : [];
if (!shots.length) throw new Error("shots[] is empty");

const app_token = $('获取任务表信息').first().json.app_token;
const table_id  = $('获取脚本表信息').first().json.table_id;
const token     = $('Auth:getAccessToken auth1').first().json.tenant_access_token;

const parentRecordId = $('读取记录').first().json.data.record.record_id;
const fields = $('读取记录').first().json.data.record.fields || {};

// ---------- helpers ----------
function toText(v) {
  if (v == null) return "";
  if (typeof v === "string") return v;
  if (Array.isArray(v) && v.length) {
    if (v[0]?.text != null) return String(v[0].text);
    return String(v[0]);
  }
  return String(v);
}

function getText(obj, name) {
  if (!obj) return "";
  return toText(obj[name]);
}

// ---------- values from task record (fields) / root fallback ----------
const AI达人_fromTask = getText(fields, "使用AI达人") || getText(fields, "AI达人");
const 产品名称_fromTask = getText(fields, "产品名称");
const 口播文案_fromTask = getText(fields, "口播文案");
const 达人上身图url = getText(fields, "达人上身图url"); // 你说的是文本

// root 也可能带（你给的入参 root 有 产品名称）
const AI达人_fromRoot = getText(root, "AI达人");
const 产品名称_fromRoot = getText(root, "产品名称");
const 口播文案_fromRoot = getText(root, "口播文案");

// ---------- map shot -> fields ----------
function mapShotToFields(s) {
  const ai = toText(s?.AI达人) || AI达人_fromTask || AI达人_fromRoot;
  const prod = toText(s?.产品名称) || 产品名称_fromTask || 产品名称_fromRoot;

  // ✅ 关键：每镜口播优先用 shots[].voiceover
  const voiceover =
    toText(s?.voiceover) ||          // 你入参就是这个
    toText(s?.voice_over) ||         // 兼容不同命名
    toText(s?.spoken_script) ||      // 兼容不同命名
    口播文案_fromTask ||
    口播文案_fromRoot;

  return {
    "镜号": Number(s.shot_number),
    "时间段": toText(s.timestamp),
    "图片提示词": toText(s.first_frame),
    "视频提示词": toText(s.video_prompt),

    // ✅ 写入字段（分镜表里必须存在同名字段）
    "AI达人": toText(ai),
    "产品名称": toText(prod),
    "口播文案": toText(voiceover),
    "达人上身图url": toText(达人上身图url),

    // ✅ 双向关联字段：必须 string[]
    "🔥 爆款复刻任务": [String(parentRecordId)]
  };
}

// 飞书 batch_create 一次最多 100
const MAX = 100;
const batches = [];
for (let i = 0; i < shots.length; i += MAX) {
  batches.push(shots.slice(i, i + MAX));
}

// 输出多批 item（每批一个 HTTP 调用）
return batches.map((chunk) => {
  const records = chunk.map(s => ({ fields: mapShotToFields(s) }));
  return {
    json: {
      url: `https://open.feishu.cn/open-apis/bitable/v1/apps/${app_token}/tables/${table_id}/records/batch_create`,
      headers: {
        "Authorization": `Bearer ${token}`,
        "Content-Type": "application/json"
      },
      body: { records }
    }
  };
});

/**
 * 标准化输入（可整段替换）
 * - 兼容飞书字段：纯字符串 / 富文本数组([{text:""}]) / 数字
 * - 修复：时长字段为 "56s" / "1分56秒" / "00:56" / "01:56" 等格式时解析失败导致回退默认值
 * - 计算：durationSec / segSeconds -> nSegments
 * - ✅ 新增：提取爆款脚本总结（viralScriptSummaryRaw / viralScriptSummary）
 * - 输出：后续节点直接使用
 */

const root0 = $input.first()?.json;
const root = Array.isArray(root0) ? root0[0] : root0;

if (!root) throw new Error("input is empty");

const rec =
  root?.data?.record?.fields ||
  root?.data?.record?.record?.fields || // 兜底（有些节点会多包一层）
  root?.record?.fields ||
  root?.fields ||
  {};

// -------------------- helpers: text / number --------------------
function toText(v) {
  if (v == null) return "";
  if (Array.isArray(v)) {
    // 飞书富文本：[{text:"..."}] 或附件数组 / 其它数组
    return v
      .map((x) => {
        if (x == null) return "";
        if (typeof x === "string") return x;
        if (typeof x === "number") return String(x);
        if (typeof x === "object") return x.text ?? x.name ?? x.value ?? "";
        return String(x);
      })
      .filter(Boolean)
      .join("\n")
      .trim();
  }
  if (typeof v === "object") return String(v.text ?? v.value ?? v.name ?? "").trim();
  return String(v).trim();
}

function toNumber(v) {
  // 更宽松：能从 "56s" 里抠出 56
  if (v == null) return NaN;
  if (typeof v === "number" && Number.isFinite(v)) return v;

  const s = toText(v);
  if (!s) return NaN;

  // 先尝试直接 Number()
  const direct = Number(s);
  if (Number.isFinite(direct)) return direct;

  // 再尝试提取首个数字（含小数）
  const m = s.match(/(\d+(\.\d+)?)/);
  if (m) {
    const n = Number(m[1]);
    if (Number.isFinite(n)) return n;
  }
  return NaN;
}

/**
 * 把时长字段解析成秒数
 * 支持：
 * - 56 / "56" / "56s" / "56秒" / "56 sec"
 * - "1分56秒" / "2分钟" / "1 min 20 sec"
 * - "00:56" / "01:56" / "00:01:56"
 */
function parseDurationToSec(v, fallback = 32) {
  if (v == null) return fallback;

  // 1) 直接数字
  if (typeof v === "number" && Number.isFinite(v)) return Math.max(1, Math.round(v));

  const s0 = toText(v);
  if (!s0) return fallback;

  const s = s0.trim();

  // 2) 时间格式 mm:ss 或 hh:mm:ss
  if (/^\d{1,2}:\d{2}(:\d{2})?$/.test(s)) {
    const parts = s.split(":").map((x) => parseInt(x, 10));
    if (parts.some((n) => !Number.isFinite(n))) return fallback;
    if (parts.length === 2) return parts[0] * 60 + parts[1];
    if (parts.length === 3) return parts[0] * 3600 + parts[1] * 60 + parts[2];
  }

  // 3) 含“分/分钟/min” + “秒/s/sec”
  const minMatch = s.match(/(\d+)\s*(分|分钟|min|mins|minute|minutes)/i);
  const secMatch = s.match(/(\d+)\s*(秒|s|sec|secs|second|seconds)/i);
  if (minMatch || secMatch) {
    const mins = minMatch ? parseInt(minMatch[1], 10) : 0;
    const secs = secMatch ? parseInt(secMatch[1], 10) : 0;
    const total = mins * 60 + secs;
    return total > 0 ? total : fallback;
  }

  // 4) 兜底：从任何字符串中提取数字（可把 "56s" -> 56）
  const n = toNumber(s);
  if (Number.isFinite(n) && n > 0) return Math.max(1, Math.round(n));

  return fallback;
}

// -------------------- get fields --------------------
const api_key = toText(rec["api_key"]);
const app_id = toText(rec["app_id"]);
const app_secret = toText(rec["app_secret"]);
const record_id =
  toText(rec["record_id"]) ||
  toText(rec["记录id"]) ||
  root?.data?.record?.record_id ||
  root?.data?.record?.id ||
  "";

const productDesc = toText(rec["产品卖点"] || rec["产品描述"] || "");
const productName = toText(rec["产品名称"] || "");
const language = toText(rec["视频语言"] || rec["language"] || "Chinese");
const presenterMode = toText(rec["presenterMode"] || rec["人物模式"] || "talking_head");

// ✅ 时长：支持 "56s"
const durationRaw =
  rec["时长"] ??
  rec["视频时长"] ??
  rec["时长(秒)"] ??
  rec["duration"] ??
  rec["durationSec"];

const durationSec = parseDurationToSec(durationRaw, 32);

// 分段时长（你现在默认 8；也允许未来飞书可配字段）
const segSecondsRaw = rec["分段时长"] ?? rec["segSeconds"] ?? 8;
const segSeconds = Math.max(1, Math.round(toNumber(segSecondsRaw) || 8));

// ✅ 片段数量：按 ceil 计算
const nSegments = Math.max(1, Math.ceil(durationSec / segSeconds));

// 参考爆款脚本（可选）
const refScript = toText(rec["参考脚本"] || rec["参考爆款脚本"] || rec["爆款脚本"] || "");

// 达人特征/描述（可选）
const personDescRaw = toText(rec["达人特征"] || rec["达人特征描述"] || rec["人物特征"] || "");
const personDesc = personDescRaw;

// ✅ 爆款脚本总结（你缺的就是这个）
const viralScriptSummaryRaw = toText(
  rec["爆款脚本总结"] ||
  rec["爆款脚本总结JSON"] ||
  rec["爆款脚本拆解"] ||
  rec["爆款总结"] ||
  ""
);

// 尽量把总结解析成对象（如果是 JSON 字符串）
let viralScriptSummary = null;
let viralScriptSummaryParseError = "";
if (viralScriptSummaryRaw) {
  const s = viralScriptSummaryRaw.trim();
  if (s.startsWith("{") || s.startsWith("[")) {
    try {
      viralScriptSummary = JSON.parse(s);
    } catch (e) {
      viralScriptSummaryParseError = String(e?.message || e);
      viralScriptSummary = null; // 保持可控
    }
  }
}

// -------------------- output --------------------
return [
  {
    ...root,
    api_key,
    app_id,
    app_secret,
    record_id,

    productName,
    productDesc,
    personDesc,
    presenterMode,
    language,

    durationSec,
    segSeconds,
    nSegments,

    refScript,

    // ✅ 新增输出
    viralScriptSummaryRaw,   // 原始字符串（不丢）
    viralScriptSummary,      // 解析后的对象（给后面节点直接用）

    _debug: {
      durationRaw: typeof durationRaw === "string" ? durationRaw : JSON.stringify(durationRaw),
      durationSec,
      segSeconds,
      nSegments,

      recordFieldsKeys: Object.keys(rec || {}).slice(0, 80),

      personDescLen: personDesc?.length || 0,
      refScriptLen: refScript?.length || 0,

      viralScriptSummaryLen: viralScriptSummaryRaw?.length || 0,
      viralScriptSummaryParseError,
      hasViralScriptSummary: !!viralScriptSummaryRaw,
      viralScriptSummaryType: viralScriptSummary ? (Array.isArray(viralScriptSummary) ? "array" : typeof viralScriptSummary) : "null",
    },
  },
];
